async function shredSO(task) {
    const zipPath = path.join(process.cwd(), 'So', task.file_path);
    const workDir = path.join(process.cwd(), 'So', 'work_' + task.id);

    console.log(`\n--- 🔍 STARTING DEEP AUDIT: ${task.file_path} ---`);

    try {
        // 1. UNZIP ON THE FLY
        execSync(`mkdir -p "${workDir}"`);
        console.log(`📦 Extracting ${task.file_path}...`);
        execSync(`unzip -o "${zipPath}" -d "${workDir}"`);

        // Find the actual .so file inside
        const soFile = execSync(`find "${workDir}" -name "*.so"`).toString().trim();
        if (!soFile) throw new Error("No .so file found in zip");

        // 2. BINARY METADATA AUDIT
        const info = execSync(`rabin2 -I "${soFile}"`).toString();
        const isStripped = info.includes('stripped true');
        const arch = info.match(/arch\s+(.+)/)?.[1] || 'unknown';

        // 3. GO VERSION SNIFFING
        const goVersion = execSync(`strings "${soFile}" | grep -E "go1\\.[0-9]+" | head -n 1`).toString().trim() || 'Unknown Go Version';

        // 4. FUNCTION ANALYSIS & PCLNTAB RECOVERY
        console.log('🧪 Analyzing Go structure and JNI bridges...');
        // aa = analyze, ann = go symbols, afl = list functions
        const functionsRaw = execSync(`r2 -qc "aa; ann; afl" "${soFile}"`).toString();

        const allFunctions = functionsRaw.split('\n').filter(line => line.trim());

        const jniExports = [];
        const userLogic = [];
        const runtimeTrash = [];

        allFunctions.forEach(line => {
            const parts = line.trim().split(/\s+/);
            const name = parts[parts.length - 1];
            if (!name || name.startsWith('0x')) return;

            if (name.startsWith('Java_')) {
                jniExports.push(name);
            } else if (name.startsWith('runtime.') || name.startsWith('type.') || name.startsWith('go.')) {
                runtimeTrash.push(name);
            } else {
                userLogic.push(name);
            }
        });

        // 5. REPORT GENERATION (LOG ONLY)
        console.log('\n' + '='.repeat(40));
        console.log(`AUDIT REPORT FOR: ${path.basename(soFile)}`);
        console.log(`- Architecture: ${arch}`);
        console.log(`- Stripped: ${isStripped ? 'YES (Hard Mode)' : 'NO (Easy Mode)'}`);
        console.log(`- Compiler: ${goVersion}`);
        console.log(`- JNI Bridge Entrypoints: ${jniExports.length}`);
        jniExports.forEach(e => console.log(`    -> ${e}`));
        console.log(`- User Logic Functions: ${userLogic.length}`);
        console.log(`- Runtime/Internal Bloat: ${runtimeTrash.length}`);
        console.log('='.repeat(40) + '\n');

        // Cleanup working dir
        execSync(`rm -rf "${workDir}"`);

        // Mark as audited so we don't repeat
        await supabase.from('so_analysis').update({ status: 'audited' }).eq('id', task.id);
        console.log('✅ Audit complete. Status updated to "audited".');

    } catch (err) {
        console.error('❌ Audit failed:', err.message);
        await supabase.from('so_analysis').update({ status: 'failed' }).eq('id', task.id);
    }
}

